import java.util.Scanner;

public class BufferOverflowExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string:");
        String userInput = scanner.nextLine();

        int bufferSize = 10; // Define buffer size

        // Check if user input exceeds buffer size
        if (userInput.length() > bufferSize) {
            System.out.println("User input exceeds buffer size. Truncating input.");
            userInput = userInput.substring(0, bufferSize);
        }

        char[] buffer = new char[bufferSize]; // Buffer with fixed size

        // Copy user input into buffer with proper bounds checking
        userInput.getChars(0, Math.min(userInput.length(), bufferSize), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
